class Solution:
	def maxSubArray(self, nums: list[int]) -> int:
		max_sum = float('-inf');
		sum = 0;
		for num in nums:
			sum += num;
		max_sum = max(max_sum, sum);
		sum = max(0, sum);
		return max_sum;

def main():
	nums = list(map(int, input().split()));
	s = Solution();
	print(s.maxSubArray(nums));

